registerModule('Movement Trail', function(g) {
  g._trail = g._trail || {
    points: [],
    maxLength: 48,
    lastX: g.px,
    lastY: g.py
  };

  var trail = g._trail;
  var ctx = g.ctx;
  var dx = g.px - trail.lastX;
  var dy = g.py - trail.lastY;
  var moved = dx * dx + dy * dy > 0.1;

  if (moved) {
    trail.points.push({ x: g.px, y: g.py, age: 0 });
    if (trail.points.length > trail.maxLength) {
      trail.points.shift();
    }
    trail.lastX = g.px;
    trail.lastY = g.py;
  }

  var len = trail.points.length;
  if (len < 2) return;

  for (var i = 1; i < len; i++) {
    var pt = trail.points[i];
    var prev = trail.points[i - 1];
    var t = i / len;
    var alpha = t * t * 0.85;
    var width = t * 3.5;

    // Color shifts from cyan-green to electric blue as trail ages
    var r = Math.round(g.lerp(0, 0, t));
    var gr = Math.round(g.lerp(80, 255, t));
    var b = Math.round(g.lerp(255, 170, t));

    ctx.beginPath();
    ctx.moveTo(prev.x, prev.y);
    ctx.lineTo(pt.x, pt.y);
    ctx.strokeStyle = 'rgba(' + r + ',' + gr + ',' + b + ',' + alpha + ')';
    ctx.lineWidth = width;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.stroke();
  }

  // Glow pulse at the tail origin
  if (len > 4) {
    var tail = trail.points[0];
    var pulse = 0.3 + 0.2 * Math.sin(g.tick * 0.18);
    var grad = ctx.createRadialGradient(tail.x, tail.y, 0, tail.x, tail.y, 5);
    grad.addColorStop(0, 'rgba(0,180,255,' + pulse + ')');
    grad.addColorStop(1, 'rgba(0,0,80,0)');
    ctx.beginPath();
    ctx.arc(tail.x, tail.y, 5, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();
  }
})

registerModule('Ambient Starfield', function(g) {
  g._stars = g._stars || (function() {
    var arr = [];
    for (var i = 0; i < 180; i++) {
      arr.push({
        x: Math.random() * 1600 - 800,
        y: Math.random() * 1200 - 600,
        z: Math.random() * 3 + 0.2,
        blink: Math.random() * Math.PI * 2,
        blinkSpeed: Math.random() * 0.04 + 0.005,
        size: Math.random() * 1.2 + 0.2,
        hue: Math.random() < 0.15 ? (Math.random() < 0.5 ? 200 : 280) : 0,
        sat: Math.random() < 0.15 ? 80 : 0
      });
    }
    return arr;
  })();

  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;
  var cx = W / 2;
  var cy = H / 2;
  var stars = g._stars;

  ctx.save();

  for (var i = 0; i < stars.length; i++) {
    var s = stars[i];

    // Parallax drift relative to player
    var wx = cx + s.x - g.px * (s.z * 0.04);
    var wy = cy + s.y - g.py * (s.z * 0.04);

    // Wrap around screen edges with some margin
    var margin = 60;
    if (wx < -margin) { s.x += W + margin * 2; }
    else if (wx > W + margin) { s.x -= W + margin * 2; }
    if (wy < -margin) { s.y += H + margin * 2; }
    else if (wy > H + margin) { s.y -= H + margin * 2; }

    // Slow twinkle
    s.blink += s.blinkSpeed;
    var alpha = 0.35 + 0.55 * (0.5 + 0.5 * Math.sin(s.blink));

    // Depth-based brightness
    var brightness = 60 + s.z * 25;
    var color;
    if (s.sat > 0) {
      color = 'hsla(' + s.hue + ',' + s.sat + '%,' + brightness + '%,' + alpha.toFixed(2) + ')';
    } else {
      var c = Math.round(brightness * 2.4);
      color = 'rgba(' + c + ',' + c + ',' + (c + 10) + ',' + alpha.toFixed(2) + ')';
    }

    var sz = s.size * (0.5 + s.z * 0.35);

    ctx.globalAlpha = 1;
    ctx.fillStyle = color;

    if (sz > 1.4) {
      // Larger stars get a soft glow
      var grd = ctx.createRadialGradient(wx, wy, 0, wx, wy, sz * 3.5);
      var glowColor = s.sat > 0
        ? 'hsla(' + s.hue + ',' + s.sat + '%,' + brightness + '%,'
        : 'rgba(' + Math.round(brightness*2.4) + ',' + Math.round(brightness*2.4) + ',' + Math.round(brightness*2.4+10) + ',';
      grd.addColorStop(0, glowColor + (alpha * 0.9).toFixed(2) + ')');
      grd.addColorStop(0.4, glowColor + (alpha * 0.25).toFixed(2) + ')');
      grd.addColorStop(1, glowColor + '0)');
      ctx.fillStyle = grd;
      ctx.beginPath();
      ctx.arc(wx, wy, sz * 3.5, 0, Math.PI * 2);
      ctx.fill();
    }

    // Core star dot
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(wx, wy, sz, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.restore();
})

registerModule('Pixel Glow Effect', function(g) {
  g._glow = g._glow || { pulse: 0, trails: [] };

  var glow = g._glow;
  var ctx = g.ctx;

  // Advance pulse oscillator
  glow.pulse = (glow.pulse + 0.05) % (Math.PI * 2);

  // Store trail positions (ring buffer style)
  if (g.tick % 2 === 0) {
    glow.trails.push({ x: g.px, y: g.py, age: 0 });
    if (glow.trails.length > 12) glow.trails.shift();
  }

  // Draw motion trails
  for (var i = 0; i < glow.trails.length; i++) {
    var t = glow.trails[i];
    t.age++;
    var trailAlpha = Math.max(0, 0.35 - t.age * 0.03);
    var trailSize = Math.max(0, 6 - t.age * 0.4);
    if (trailAlpha <= 0 || trailSize <= 0) continue;

    var trailGrad = ctx.createRadialGradient(t.x, t.y, 0, t.x, t.y, trailSize);
    trailGrad.addColorStop(0, 'rgba(0,255,170,' + trailAlpha + ')');
    trailGrad.addColorStop(1, 'rgba(0,255,170,0)');
    ctx.beginPath();
    ctx.arc(t.x, t.y, trailSize, 0, Math.PI * 2);
    ctx.fillStyle = trailGrad;
    ctx.fill();
  }

  // Pulsing outer glow radius
  var pulseVal = 0.5 + 0.5 * Math.sin(glow.pulse);
  var glowRadius = 18 + pulseVal * 8;
  var glowAlpha  = 0.18 + pulseVal * 0.12;

  // Outer ambient glow
  var outerGrad = ctx.createRadialGradient(g.px, g.py, 0, g.px, g.py, glowRadius);
  outerGrad.addColorStop(0,   'rgba(0,255,170,' + (glowAlpha * 1.8).toFixed(3) + ')');
  outerGrad.addColorStop(0.4, 'rgba(0,220,150,' + glowAlpha.toFixed(3) + ')');
  outerGrad.addColorStop(1,   'rgba(0,255,170,0)');

  ctx.beginPath();
  ctx.arc(g.px, g.py, glowRadius, 0, Math.PI * 2);
  ctx.fillStyle = outerGrad;
  ctx.fill();

  // Inner bright core halo
  var coreRadius = 5 + pulseVal * 2;
  var coreGrad = ctx.createRadialGradient(g.px, g.py, 0, g.px, g.py, coreRadius);
  coreGrad.addColorStop(0, 'rgba(180,255,230,0.95)');
  coreGrad.addColorStop(0.3, 'rgba(0,255,170,0.7)');
  coreGrad.addColorStop(1, 'rgba(0,255,170,0)');

  ctx.beginPath();
  ctx.arc(g.px, g.py, coreRadius, 0, Math.PI * 2);
  ctx.fillStyle = coreGrad;
  ctx.fill();

  // Sparkle rays — thin lines radiating outward
  var rayCount = 6;
  var rayOffset = glow.pulse * 0.4;
  ctx.save();
  ctx.globalAlpha = 0.15 + pulseVal * 0.1;
  ctx.strokeStyle = '#00ffaa';
  ctx.lineWidth = 0.5;
  for (var r = 0; r < rayCount; r++) {
    var angle = (r / rayCount) * Math.PI * 2 + rayOffset;
    var innerR = 3;
    var outerR = 12 + pulseVal * 6;
    ctx.beginPath();
    ctx.moveTo(g.px + Math.cos(angle) * innerR, g.py + Math.sin(angle) * innerR);
    ctx.lineTo(g.px + Math.cos(angle) * outerR, g.py + Math.sin(angle) * outerR);
    ctx.stroke();
  }
  ctx.restore();
})

registerModule('Floating Particle Spawner', function(g) {
  g._fps = g._fps || { pool: [], lastSpawn: 0 };
  var s = g._fps;
  var ctx = g.ctx;
  var W = g.canvas.width, H = g.canvas.height;

  if (g.tick - s.lastSpawn > 20 && s.pool.length < 60) {
    s.lastSpawn = g.tick;
    for (var n = 0; n < 2; n++) {
      var angle = Math.random() * Math.PI * 2;
      var dist = 100 + Math.random() * 250;
      var px = g.px + Math.cos(angle) * dist;
      var py = g.py + Math.sin(angle) * dist;
      px = ((px % W) + W) % W;
      py = ((py % H) + H) % H;
      var hue = Math.floor(g.rand(140, 300));
      s.pool.push({
        x: px, y: py,
        vx: g.rand(-0.4, 0.4), vy: g.rand(-0.4, 0.4),
        radius: g.rand(2, 5), hue: hue,
        pulse: g.rand(0, Math.PI * 2),
        pulseSpeed: g.rand(0.02, 0.06),
        score: Math.ceil(g.rand(1, 3))
      });
    }
  }

  var i = s.pool.length;
  while (i--) {
    var p = s.pool[i];
    p.pulse += p.pulseSpeed;
    p.x += p.vx + Math.sin(p.pulse * 0.7) * 0.3;
    p.y += p.vy + Math.cos(p.pulse) * 0.3;

    // Gentle drift toward center
    var dx = W/2 - p.x, dy = H/2 - p.y;
    var dc = Math.sqrt(dx*dx + dy*dy);
    if (dc > 50) { p.vx += (dx/dc) * 0.002; p.vy += (dy/dc) * 0.002; }

    // Clamp speed
    var spd = Math.sqrt(p.vx*p.vx + p.vy*p.vy);
    if (spd > 1) { p.vx = (p.vx/spd); p.vy = (p.vy/spd); }

    // Absorption check
    var adx = g.px - p.x, ady = g.py - p.y;
    var ad = Math.sqrt(adx*adx + ady*ady);
    if (ad < 10 + p.radius) {
      g.score += p.score * 10;
      g.absorbed = (g.absorbed || 0) + 1;
      // Burst particles
      for (var b = 0; b < 4; b++) {
        var ba = g.rand(0, Math.PI*2);
        g.particles.push({
          x: p.x, y: p.y,
          vx: Math.cos(ba) * g.rand(1,3), vy: Math.sin(ba) * g.rand(1,3),
          life: 1.0, decay: g.rand(0.04, 0.08),
          radius: g.rand(1, 3),
          color: 'hsl(' + p.hue + ',80%,70%)'
        });
      }
      s.pool.splice(i, 1);
      continue;
    }

    // Remove if way off screen
    if (p.x < -80 || p.x > W+80 || p.y < -80 || p.y > H+80) {
      s.pool.splice(i, 1); continue;
    }

    // Draw glow
    var r = Math.max(0.5, p.radius + Math.sin(p.pulse) * 1.2);
    var alpha = 0.6 + 0.3 * Math.sin(p.pulse);
    ctx.save();
    ctx.globalAlpha = alpha * 0.3;
    var grad = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, r * 3);
    grad.addColorStop(0, 'hsl(' + p.hue + ',80%,70%)');
    grad.addColorStop(1, 'hsla(' + p.hue + ',80%,70%,0)');
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(p.x, p.y, r * 3, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.fillStyle = 'hsl(' + p.hue + ',80%,70%)';
    ctx.shadowColor = 'hsl(' + p.hue + ',80%,70%)';
    ctx.shadowBlur = 8;
    ctx.beginPath();
    ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }

  // Draw shared burst particles
  var j = g.particles.length;
  while (j--) {
    var pt = g.particles[j];
    if (!pt.decay) continue;
    pt.x += pt.vx; pt.y += pt.vy;
    pt.vx *= 0.92; pt.vy *= 0.92;
    pt.life -= pt.decay;
    if (pt.life <= 0) { g.particles.splice(j, 1); continue; }
    ctx.save();
    ctx.globalAlpha = pt.life * 0.8;
    ctx.fillStyle = pt.color;
    ctx.beginPath();
    ctx.arc(pt.x, pt.y, Math.max(0.5, pt.radius * pt.life), 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }
});

registerModule('Score HUD', function(g) {
  var ctx = g.ctx;
  ctx.save();
  ctx.fillStyle = '#00ffaa';
  ctx.font = '14px Courier New';
  ctx.textAlign = 'left';
  ctx.globalAlpha = 0.8;
  ctx.fillText('Score: ' + g.score, 16, 28);
  ctx.fillText('Absorbed: ' + (g.absorbed || 0), 16, 46);
  if (g.stage > 0) ctx.fillText('Stage: ' + g.stage, 16, 64);
  ctx.restore();
});

registerModule('Score HUD', function(g) {
  g._hud = g._hud || { pulse: 0, lastScore: 0, flashTimer: 0 };

  var h = g._hud;
  var ctx = g.ctx;

  // Detect score change for flash effect
  if (g.score !== h.lastScore) {
    h.flashTimer = 18;
    h.lastScore = g.score;
  }
  if (h.flashTimer > 0) h.flashTimer--;

  h.pulse = (h.pulse + 0.05) % (Math.PI * 2);

  var pulseAlpha = 0.7 + 0.3 * Math.sin(h.pulse);
  var flashBoost = h.flashTimer > 0 ? (h.flashTimer / 18) : 0;

  var stageColors = ['#00ffaa', '#44ffcc', '#88ffdd', '#aaffee', '#ccffff', '#ffffff'];
  var stageColor = stageColors[Math.min(g.stage, stageColors.length - 1)];

  ctx.save();

  // --- Score Panel ---
  var panelX = 16;
  var panelY = 16;
  var panelW = 180;
  var panelH = 64;
  var cornerR = 8;

  // Panel background
  ctx.beginPath();
  ctx.moveTo(panelX + cornerR, panelY);
  ctx.lineTo(panelX + panelW - cornerR, panelY);
  ctx.quadraticCurveTo(panelX + panelW, panelY, panelX + panelW, panelY + cornerR);
  ctx.lineTo(panelX + panelW, panelY + panelH - cornerR);
  ctx.quadraticCurveTo(panelX + panelW, panelY + panelH, panelX + panelW - cornerR, panelY + panelH);
  ctx.lineTo(panelX + cornerR, panelY + panelH);
  ctx.quadraticCurveTo(panelX, panelY + panelH, panelX, panelY + panelH - cornerR);
  ctx.lineTo(panelX, panelY + cornerR);
  ctx.quadraticCurveTo(panelX, panelY, panelX + cornerR, panelY);
  ctx.closePath();
  ctx.fillStyle = 'rgba(4, 6, 15, 0.75)';
  ctx.fill();

  // Panel border glow
  var borderAlpha = (0.4 + 0.4 * flashBoost) * pulseAlpha;
  ctx.strokeStyle = 'rgba(' + (flashBoost > 0 ? '255,220,80' : '0,255,170') + ',' + borderAlpha + ')';
  ctx.lineWidth = 1.5 + flashBoost * 2;
  ctx.stroke();

  // SCORE label
  ctx.font = '10px monospace';
  ctx.letterSpacing = '2px';
  ctx.fillStyle = 'rgba(0,255,170,0.5)';
  ctx.fillText('SCORE', panelX + 14, panelY + 18);

  // Score value
  var scoreStr = String(g.score);
  var scoreFontSize = scoreStr.length > 7 ? 18 : 22;
  ctx.font = 'bold ' + scoreFontSize + 'px monospace';
  ctx.fillStyle = flashBoost > 0
    ? 'rgba(255,' + Math.floor(200 + 55 * flashBoost) + ',80,' + pulseAlpha + ')'
    : (stageColor);
  if (flashBoost > 0) {
    ctx.shadowColor = 'rgba(255,220,80,0.9)';
    ctx.shadowBlur = 12 * flashBoost;
  } else {
    ctx.shadowColor = stageColor;
    ctx.shadowBlur = 6 * pulseAlpha;
  }
  ctx.fillText(scoreStr, panelX + 14, panelY + 48);

  ctx.shadowBlur = 0;

  // --- Absorbed Panel ---
  var ap = { x: panelX, y: panelY + panelH + 8, w: panelW, h: 40 };

  ctx.beginPath();
  ctx.moveTo(ap.x + cornerR, ap.y);
  ctx.lineTo(ap.x + ap.w - cornerR, ap.y);
  ctx.quadraticCurveTo(ap.x + ap.w, ap.y, ap.x + ap.w, ap.y + cornerR);
  ctx.lineTo(ap.x + ap.w, ap.y + ap.h - cornerR);
  ctx.quadraticCurveTo(ap.x + ap.w, ap.y + ap.h, ap.x + ap.w - cornerR, ap.y + ap.h);
  ctx.lineTo(ap.x + cornerR, ap.y + ap.h);
  ctx.quadraticCurveTo(ap.x, ap.y + ap.h, ap.x, ap.y + ap.h - cornerR);
  ctx.lineTo(ap.x, ap.y + cornerR);
  ctx.quadraticCurveTo(ap.x, ap.y, ap.x + cornerR, ap.y);
  ctx.closePath();
  ctx.fillStyle = 'rgba(4, 6, 15, 0.65)';
  ctx.fill();
  ctx.strokeStyle = 'rgba(0,200,140,0.25)';
  ctx.lineWidth = 1;
  ctx.stroke();

  // Absorbed label
  ctx.font = '10px monospace';
  ctx.letterSpacing = '2px';
  ctx.fillStyle = 'rgba(0,200,140,0.45)';
  ctx.fillText('ABSORBED', ap.x + 14, ap.y + 16);

  // Absorbed count
  ctx.font = 'bold 16px monospace';
  ctx.fillStyle = 'rgba(0,220,160,0.85)';
  ctx.shadowColor = 'rgba(0,255,170,0.4)';
  ctx.shadowBlur = 4;
  ctx.fillText(String(g.absorbed || 0), ap.x + 14, ap.y + 32);
  ctx.shadowBlur = 0;

  // --- Stage Indicator ---
  var si = { x: panelX, y: ap.y + ap.h + 8 };
  ctx.font = '10px monospace';
  ctx.letterSpacing = '2px';
  ctx.fillStyle = 'rgba(0,200,140,0.4)';
  ctx.fillText('STAGE', si.x + 14, si.y + 12);

  var dotSpacing = 22;
  for (var i = 0; i <= 5; i++) {
    var dx = si.x + 14 + i * dotSpacing;
    var dy = si.y + 26;
    var filled = i <= g.stage;
    ctx.beginPath();
    ctx.arc(dx, dy, filled ? 6 : 4, 0, Math.PI * 2);
    if (filled) {
      ctx.fillStyle = stageColor;
      ctx.shadowColor = stageColor;
      ctx.shadowBlur = 8;
    } else {
      ctx.fillStyle = 'rgba(0,80,60,0.5)';
      ctx.shadowBlur = 0;
    }
    ctx.fill();
    ctx.shadowBlur = 0;
  }

  ctx.restore();
})

registerModule('Background Grid', function(g) {
  g._grid = g._grid || {
    offsetX: 0,
    offsetY: 0,
    prevPx: g.px,
    prevPy: g.py,
    pulse: 0
  };

  var grid = g._grid;
  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;

  // Track camera scroll from player movement
  var dx = g.px - grid.prevPx;
  var dy = g.py - grid.prevPy;
  grid.prevPx = g.px;
  grid.prevPy = g.py;

  grid.offsetX = (grid.offsetX - dx * 0.4) % 60;
  grid.offsetY = (grid.offsetY - dy * 0.4) % 60;

  // Pulse based on player speed
  var speed = Math.sqrt(g.vx * g.vx + g.vy * g.vy);
  grid.pulse = grid.pulse + (speed * 0.04 - grid.pulse) * 0.08;

  var cellSize = 60;
  var alpha = 0.045 + grid.pulse * 0.12;
  var glowAlpha = 0.018 + grid.pulse * 0.06;

  // Draw subtle glow lines first (wider, very transparent)
  ctx.save();
  ctx.lineWidth = 3;

  var startX = (grid.offsetX % cellSize + cellSize) % cellSize - cellSize;
  var startY = (grid.offsetY % cellSize + cellSize) % cellSize - cellSize;

  // Glow pass
  ctx.strokeStyle = 'rgba(0, 255, 170, ' + glowAlpha + ')';
  ctx.beginPath();
  for (var x = startX; x <= W + cellSize; x += cellSize) {
    ctx.moveTo(x, 0);
    ctx.lineTo(x, H);
  }
  for (var y = startY; y <= H + cellSize; y += cellSize) {
    ctx.moveTo(0, y);
    ctx.lineTo(W, y);
  }
  ctx.stroke();

  // Sharp pass
  ctx.lineWidth = 0.5;
  ctx.strokeStyle = 'rgba(0, 200, 140, ' + alpha + ')';
  ctx.beginPath();
  for (var x2 = startX; x2 <= W + cellSize; x2 += cellSize) {
    ctx.moveTo(x2, 0);
    ctx.lineTo(x2, H);
  }
  for (var y2 = startY; y2 <= H + cellSize; y2 += cellSize) {
    ctx.moveTo(0, y2);
    ctx.lineTo(W, y2);
  }
  ctx.stroke();

  // Draw intersection dots that pulse with movement
  var dotAlpha = 0.06 + grid.pulse * 0.2;
  var dotSize = 1 + grid.pulse * 1.5;
  ctx.fillStyle = 'rgba(0, 255, 170, ' + dotAlpha + ')';
  for (var xi = startX; xi <= W + cellSize; xi += cellSize) {
    for (var yi = startY; yi <= H + cellSize; yi += cellSize) {
      ctx.beginPath();
      ctx.arc(xi, yi, dotSize, 0, 6.2832);
      ctx.fill();
    }
  }

  ctx.restore();
})
